cd /workspaces/typescript-node/lambench-pro && bun -e "
import { plan, TaskType } from './apps/server/src/rlm/LambdaPlan.ts';
// Find an n where merge.kStar < concat.kStar (the property should hold when not capped)
// merge: kStar = ceil(sqrt(n * 1.0 / 2.0))
// concat: kStar = ceil(n / K) (near-free)
// For n=600_000, K=100_000:
//   concat.kStar = ceil(6) = 6
//   merge.kStar = ceil(sqrt(300000)) = ceil(547) -> capped at 20
// For n=150_000:
//   concat.kStar = ceil(1.5) = 2
//   merge.kStar = ceil(sqrt(75000)) = ceil(273) -> capped at 20
// We need merge to NOT be capped. sqrt(n/2) < 20 → n < 800. But then n<=K, fast path.
// The property only holds when merge.kStar is NOT capped.
// Let's test with a tiny K instead:
const merge = plan(TaskType.SUMMARIZATION, 400, 100, 0.8, 0.95, 0.9);
const concat = plan(TaskType.TRANSLATION, 400, 100, 0.8, 0.95, 0.9);
console.log('K=100 merge:', merge.kStar, 'concat:', concat.kStar);
// sqrt(400*1/2) = sqrt(200) = 14.1 -> ceil = 15
// concat = ceil(400/100) = 4
console.log('property holds:', merge.kStar >= concat.kStar); // expensive ⊕ = LARGER k* (minimise call count)
" 2>&1

